export interface IColor {
    id: number;
    name: string;
    hex: string;
}

export interface ISize {
    id: number;
    name: string;
}

export interface ICategory {
    id: number;
    name: string;
    parentId: number | null;
}

export type Gender = "F" | "M";

export interface IStock {
    id: number;
    sizeId: number;
    colorId: number;
    gender: Gender;
    quantity: number;
    colorName: string;
    colorHex: string;
    sizeName: string;
}

export interface ISettings {
    colors: IColor[];
    sizes: ISize[];
    categories: ICategory[];
    stocks: IStock[];
}

export interface IAddress {
    cep: string;
    state: string;
    city: string;
    street: string;
    neighborhood: string;
}

export interface IDeliveryEstimate {
    deliveryValue: number;
    deliveryForecast: number;
}

export enum DocumentType { cpf, cnpj }

export enum CepStatus { incomplete, loading, invalid, valid }

export interface CheckEmailRes {
    registered: boolean;
}

export interface IUser {
    firstName: string;
    lastName: string;
    phone: string;
    email: string;
    document: string;
    documentType: DocumentType;
    zipcode: string;
    street: string;
    number: string;
    complement: string;
    city: string;
    state: string;
    neighborhood: string;
    reference: string | null;
}

export interface IItem {
    productId: number;
    stockId: number;
    colorId: number;
    sizeId: number;
    quantity: number;
    name: string;
    unitPrice: number;
    picture: string;
}

export interface ICartRes {
    couponValue: number;
    deliveryForecast: number;
    deliveryValue: number;
    isValidCoupon: boolean;
    productsValue: number;
    totalValue: number;
}

export type Picture = {
	pictureId: string;
	colorId: number;
	index: number;
};

export interface IProduct {
	id: number;
	categoryId: number;
	name: string;
	price: number;
	oldPrice: number;
	mainPictureId: string;
	mainPictureColorId: number;
	isPaused: boolean;
	description: string;
	gender: Gender;
}

export interface IDetailedProduct extends IProduct {
	pictures: Picture[];
	tags: ITag[];
}

export type ITag = {
	id: number;
	name: string;
};
