import React, { useEffect, useState } from "react";
import { IAddress, IDeliveryEstimate } from "../types/types";
import cep from "cep-promise";
import { isBrowser } from "../utils/utils";
import api from "../components/api";

class AddressStorage {
  private static STORAGE_KEY = "address";

  public static get(): IAddress | null {
    const storedAddress = isBrowser && window.localStorage.getItem(AddressStorage.STORAGE_KEY);
    return storedAddress ? JSON.parse(storedAddress) : null;
  }

  public static add(addr: IAddress): void {
    if (isBrowser) window.localStorage.setItem(AddressStorage.STORAGE_KEY, JSON.stringify(addr));
  }

  public static remove(): void {
    if (isBrowser) window.localStorage.removeItem(AddressStorage.STORAGE_KEY);
  }
}

const useAddress = () => {
  const [cacheAddress, setCacheAddress] = useState<IAddress | null>(AddressStorage.get());

  const searchCepAndStoreLocal = async (cepStr: string): Promise<IAddress> => {
    let formatted = cepStr.replace(/\D/g, '');
    if (formatted.length === 8) {
      return cep(formatted)
        .then((cepRes) => {
          const result: IAddress = {
            cep: cepRes.cep,
            state: cepRes.state,
            city: cepRes.city,
            street: cepRes.street,
            neighborhood: cepRes.neighborhood
          }
          AddressStorage.add(result);
          setCacheAddress(result);
          return result;
        }).catch((err) => {
          AddressStorage.remove();
          setCacheAddress(null);
          throw "Cep inválido";
        })
    } else {
      AddressStorage.remove();
      setCacheAddress(null);
      throw "Cep deve possuir 8 dígitos";
    }
  };

  const deliveryEstimate = async (cepStr: string, state: string, city: string, productsValue: number): Promise<IDeliveryEstimate> => {
    return api.post("/v1/delivery-estimate", {
      zipcode: cepStr.replace(/\D/g, ''),
      state,
      city,
      productsValue
    })
      .then((res) => {
        const estimate: IDeliveryEstimate = res.data;
        return estimate;
      }).catch((e) => {
        console.log('Error: ', e);
        throw "Não foi possível obter a estimativa";
      });
  };

  return { cacheAddress, searchCepAndStoreLocal, deliveryEstimate };
};

export default useAddress;